INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$PeopleGPT natural-language search$q$, $q$Search 800M+ candidate profiles using plain-English queries instead of Boolean strings.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$AI sourcing Agents$q$, $q$Always-on agents that learn from recruiter feedback and continuously resurface new matching candidates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Contact enrichment$q$, $q$Credit-based unlocking of verified emails and phone numbers for shortlisted candidates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Automated outreach sequencing$q$, $q$Personalized, multi-step candidate outreach campaigns launched directly from search results.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$ATS integrations$q$, $q$Native two-way sync with Greenhouse, Lever, Ashby, Workday, SmartRecruiters, iCIMS and dozens more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Unlimited searches and shortlists$q$, $q$All paid plans include unlimited searches and unlimited saved candidates per project.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Team collaboration and projects$q$, $q$Shared projects let recruiting teams organize searches, shortlists and notes by role.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Relevance-ranked results$q$, $q$Candidates are ranked and explained by match relevance rather than returned as a flat keyword list.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Natural-language search dramatically speeds up sourcing versus manual Boolean strings$q$, 0);
