INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Broad ATS integration coverage fits into existing recruiting workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Backed by major investors (Sequoia, DST Global) with fast enterprise adoption$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Per-seat pricing plus separate Agent and contact-credit add-ons can raise total cost quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$No public entry-level paid tier below $139/seat/month$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Business (enterprise) pricing is not published and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Contact data accuracy depends on third-party sourcing and can vary by region$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Relatively young company (founded 2022) compared to established sourcing incumbents$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$What is Juicebox (PeopleGPT)?$q$, $q$Juicebox is an AI recruiting platform built around PeopleGPT, a natural-language search engine that lets recruiters find candidates by describing them in plain English rather than writing Boolean search queries.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$How much does Juicebox cost?$q$, $q$Juicebox offers a free trial with limited searches, a Starter plan at $139 per seat per month, a Growth plan at $199 per seat per month, and a custom-priced Business plan; annual billing saves roughly 15%.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Who founded Juicebox and when?$q$, $q$Juicebox was founded in 2022 by David Paffenholz and Ishan Gupta in San Francisco, launching through Y Combinator's Summer 2022 batch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Does Juicebox integrate with applicant tracking systems?$q$, $q$Yes, Juicebox integrates natively with dozens of ATS platforms including Greenhouse, Lever, Ashby, Workday, BambooHR, SmartRecruiters and iCIMS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$What are Juicebox AI Agents?$q$, $q$AI Agents are always-on sourcing automations, sold as a $199-per-agent-per-month add-on, that continuously search and learn from a recruiter's approvals and rejections to keep candidate pipelines fresh.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$How much has Juicebox raised in funding?$q$, $q$Juicebox has raised roughly $36 million in early funding including a $30 million Sequoia-led Series A, followed by an $80 million Series B in March 2026 led by DST Global at an $850 million valuation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Passive candidate sourcing$q$, $q$Recruiters use natural-language search to find passive candidates who don't use standard job-title keywords in their profiles.$q$, $q$In-house talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Always-on pipeline building$q$, $q$Agencies deploy AI Agents to continuously refresh candidate shortlists for hard-to-fill or recurring roles.$q$, $q$Recruiting and staffing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$High-volume technical hiring$q$, $q$Fast-growing technology companies use Juicebox to source engineering and AI talent at scale with ATS-integrated workflows.$q$, $q$Tech company hiring managers and recruiters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Free Trial$q$, $q$Free$q$, $q$trial$q$, NULL, $q$["Limited number of searches","Access to candidate database","No credit card sourcing agents"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Starter$q$, $q$$139/seat/month$q$, $q$monthly (annual ~15% less)$q$, NULL, $q$["Unlimited searches","Unlimited shortlisted candidates","Contact credits","ATS integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Growth$q$, $q$$199/seat/month$q$, $q$monthly (annual ~15% less)$q$, NULL, $q$["Everything in Starter","Higher contact credit allowance","Team collaboration features","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$Business$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Custom seat and credit volumes","Dedicated account support","Advanced admin controls","Enterprise ATS integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Juicebox is an AI-native recruiting platform built around PeopleGPT, a natural-language search engine that lets recruiters describe a candidate in plain English instead of constructing Boolean search strings. Founded in San Francisco in 2022 by David Paffenholz and Ishan Gupta and launched out of Y Combinator, the company has grown quickly, closing an $80 million Series B at an $850 million valuation in March 2026 after tripling annual recurring revenue in under a year.$q$, $q$The platform searches across more than 800 million public professional profiles and returns ranked, relevant matches based on the intent behind a query rather than exact keyword matches. This makes it useful for sourcing passive candidates whose profiles do not use the exact job titles or skill terms a recruiter would otherwise search for.$q$, $q$Juicebox has expanded from a pure search tool into a fuller sourcing workflow product, adding autonomous AI Agents, outreach sequencing, contact enrichment, and native ATS integrations so that recruiters can move from search to outreach without leaving the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The centerpiece feature is natural-language candidate search: recruiters type a free-text description of role requirements, seniority, skills, and location, and the underlying LLM converts that into a structured query executed against Juicebox's profile index, returning ranked candidates with explanations of match relevance.$q$, $q$AI sourcing Agents extend this by running continuously in the background rather than on demand. An Agent learns from which candidates a recruiter approves or rejects, adapts its criteria over time, and delivers fresh candidate batches automatically, which is positioned as a way to keep a sourcing pipeline warm without recurring manual searches.$q$, $q$Rounding out the platform, Juicebox offers contact-credit-based email and phone enrichment, personalized outreach sequencing, and two-way integrations with major applicant tracking systems (Greenhouse, Lever, Ashby, Workday, SmartRecruiters, iCIMS and dozens of others), letting sourced candidates flow directly into a recruiting team's existing pipeline.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cc45ff7-31f0-4735-be09-538439350dbc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Juicebox uses a seat-based subscription model with a free trial offering a limited number of searches. Paid tiers are Starter at $139 per seat per month and Growth at $199 per seat per month, with a custom-quoted Business plan for larger recruiting teams needing advanced controls, dedicated support, or higher usage limits. Annual billing discounts the monthly rate by roughly 15 percent.$q$, $q$AI Agents are not bundled into the base seat price; they are sold as a separate add-on at $199 per agent per month on any paid plan. Contact credits used to unlock verified emails and phone numbers are also metered, so total cost scales with both the number of seats and the volume of outreach a team runs.$q$]::text[], 2);
