INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Multi-factor authentication (MFA)$q$, $q$Push, TOTP, and hardware-key MFA enforced at the directory level.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$LDAP and RADIUS as a service$q$, $q$Cloud-hosted LDAP and RADIUS so legacy apps and Wi-Fi networks authenticate against the same directory.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Conditional access policies$q$, $q$Access rules based on device trust, location, and risk signals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Password manager$q$, $q$Built-in end-user password manager included in SSO and higher packages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Zero Trust and SaaS management$q$, $q$Visibility into shadow SaaS usage and Zero Trust access controls in the Platform Prime tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Generous free tier covers up to 10 users with real identity and device features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Cross-platform support for Windows, macOS and Linux in one directory$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Flexible a la carte pricing lets small teams pay only for needed modules$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Unifies human and non-human identity management in one console$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Reduces or eliminates need for on-premises Active Directory infrastructure$q$, 4);
