INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Feature breadth means a learning curve for teams new to unified IT management$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$What is JumpCloud?$q$, $q$JumpCloud is a cloud-based directory platform that centralizes identity, device, and access management, functioning as a modern, cross-platform alternative to on-premises Active Directory.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Is JumpCloud free?$q$, $q$Yes, JumpCloud offers a free plan covering up to 10 users with core identity and device management features; paid plans start at $9/user/month for Device Management.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$When was JumpCloud founded?$q$, $q$JumpCloud was founded in 2012 and is headquartered in Louisville, Colorado.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Does JumpCloud replace Active Directory?$q$, $q$JumpCloud is commonly used to replace or reduce dependence on on-premises Active Directory by moving directory services, SSO, MFA, and device management to the cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$What operating systems does JumpCloud support?$q$, $q$JumpCloud provides native device management for Windows, macOS, and Linux endpoints.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$How much funding has JumpCloud raised?$q$, $q$JumpCloud has raised approximately $462 million total, reaching a $2.63 billion valuation after an October 2021 round led by Sapphire Ventures and BlackRock.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Replacing on-prem Active Directory$q$, $q$IT teams migrate identity and device management to JumpCloud's cloud directory to eliminate on-premises AD servers.$q$, $q$IT administrators at small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Unified SSO and MFA rollout$q$, $q$Organizations centralize SaaS application access behind single sign-on and enforce MFA across all users from one console.$q$, $q$IT and security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Cross-platform device fleet management$q$, $q$Companies with mixed Windows, macOS, and Linux fleets manage patching and policy from a single MDM console.$q$, $q$IT operations and MSPs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 10 users","Core identity management","Core device management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Device Management$q$, $q$$9/user/month (annual)$q$, $q$monthly or annual$q$, NULL, $q$["Device management and MDM","Policy enforcement","Patch management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$SSO$q$, $q$$11/user/month (annual)$q$, $q$monthly or annual$q$, NULL, $q$["SSO and MFA access to resources","Password Manager included"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$Platform / Platform Prime$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Unified identity, device and access management","Zero Trust security (Prime)","AI and SaaS management (Prime)","Premium support (Prime)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JumpCloud is a cloud directory platform designed to replace or modernize on-premises Active Directory by centralizing identity, device, and access management in a single cloud console. Founded in 2012 and headquartered in Louisville, Colorado, the company built its platform to work natively across Windows, macOS, and Linux, and to connect to cloud infrastructure and thousands of SaaS applications rather than being tied to a single vendor ecosystem.$q$, $q$The platform's directory sits at the center of an IT admin's stack: it authenticates users, manages devices, and enforces access policies, while modules for SSO, MFA, LDAP, RADIUS, and mobile device management extend that directory outward to specific use cases. This modular approach lets IT teams adopt JumpCloud incrementally rather than migrating an entire identity stack at once.$q$, $q$JumpCloud has scaled through eight-plus years of venture funding, reaching a $2.63 billion valuation in 2021, and has grown its product to include Zero Trust security and SaaS/shadow-IT visibility features aimed at addressing the sprawl of cloud tools that small and mid-sized IT teams now have to manage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$JumpCloud's Cloud Directory Platform provides a central identity store that supports both human users and non-human identities (API keys, service accounts), with cross-platform device management (MDM) covering patch management, policy enforcement, and remote actions for Windows, macOS, and Linux endpoints.$q$, $q$Access management features include single sign-on to SAML and OIDC-based SaaS applications, multi-factor authentication (including push, TOTP, and hardware key support), conditional access policies based on device trust and location, and a built-in password manager for end users.$q$, $q$For infrastructure-level authentication, JumpCloud offers LDAP-as-a-service and RADIUS-as-a-service so legacy on-premises applications and Wi-Fi networks can authenticate against the same cloud directory, along with directory insights and reporting, Zero Trust security controls, and newer AI/SaaS management tooling that surfaces unmanaged or unsanctioned application usage across an organization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JumpCloud offers a free tier for organizations with up to 10 users that includes core identity and device management functionality, making it accessible to very small teams before they need to pay. Beyond that, pricing follows an a la carte, per-user-per-month model: individual features such as Cloud Directory, MFA, SSO, User Lifecycle Management, and Password Manager are priced separately (roughly $3-6/user/month annually), while pre-bundled packages combine common feature sets: Device Management at $9/user/month, SSO at $11/user/month, and Device Identity Management at $13/user/month (annual billing; monthly billing runs $2/user higher on each).$q$, $q$For organizations wanting a single unified solution rather than assembling modules, JumpCloud offers Platform Essentials (capped at 300 users), Platform, and Platform Prime bundles, all priced via custom sales quote, with Platform Prime adding Zero Trust, AI and SaaS management, and premium support. A 30-day free trial is available across the product line, and JumpCloud offers custom discounted rates for education and nonprofit organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e87fc9fe-9139-4e2a-b348-1b4b64fe9eeb', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
