INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Established operations with unique processes may need developer customization$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Limited to CSA/cooperative use cases rather than general nonprofit management$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$What is juntagrico used for?$q$, $q$juntagrico is open-source software used by Community-Supported Agriculture (CSA) cooperatives to manage members, product subscriptions, cooperative shares, volunteer labor coordination, and weekly delivery logistics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Is juntagrico free?$q$, $q$Yes, juntagrico is free and open source. Organizations can self-host it at no licensing cost, or join the Verein Juntagrico association for free shared hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$What technology is juntagrico built on?$q$, $q$juntagrico is built with Python and the Django web framework, with its source code publicly available on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Who maintains juntagrico?$q$, $q$The Verein Juntagrico, a nonprofit association of CSA organizations, coordinates ongoing development and governance of the software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$How many organizations use juntagrico?$q$, $q$juntagrico is used in production by more than 25 Community-Supported Agriculture organizations, primarily in Switzerland.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Does juntagrico support invoicing?$q$, $q$Yes, an optional extension adds support for Swiss QR-bill invoicing of cooperative members.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$CSA member and share administration$q$, $q$Cooperatives track member enrollment, cooperative share deposits, and subscription sizes in one system.$q$, $q$CSA/Solawi cooperative administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Volunteer labor scheduling$q$, $q$Organizers coordinate mandatory co-worker duty assignments required by many CSA membership models.$q$, $q$CSA volunteer coordinators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Weekly distribution logistics$q$, $q$Depot managers generate delivery lists per collection point based on current subscriptions each week.$q$, $q$CSA distribution and depot organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Self-hosted$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full open-source Django codebase","Unlimited members and subscriptions","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$Verein Juntagrico membership$q$, $q$Free (association membership)$q$, $q$n/a$q$, NULL, $q$["Shared hosted instance","Voice in software roadmap","Access to association support network"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$juntagrico is an open-source management platform built specifically for Community-Supported Agriculture (CSA) organizations, known as 'Solawi' in Switzerland and other German-speaking regions. It grew out of internal software originally built for the Swiss CSA cooperative Ortoloco and was rebuilt starting in 2017 so other CSA groups could adopt it independently.$q$, $q$The software is written in Python using the Django web framework, with its source code openly available on GitHub for self-hosting or contribution. Ongoing development is coordinated by the nonprofit Verein Juntagrico association, which gives member organizations a voice in the product roadmap and offers free shared hosting to association members.$q$, $q$juntagrico is now used in production by more than 25 CSA operations across Switzerland, addressing the operational needs unique to share-based agricultural cooperatives: member administration, share tracking, volunteer coordination, and weekly distribution logistics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality centers on member and subscription management: tracking who belongs to the cooperative, what share size or product subscription each member holds, and their cooperative capital deposits. This is paired with tools for coordinating the mandatory co-worker (volunteer labor) obligations that many CSA models require of members.$q$, $q$For distribution, juntagrico generates weekly delivery and depot (collection point) lists so organizers know exactly what quantities need to go to each distribution site, along with reporting tools to reconcile subscriptions against available harvest.$q$, $q$Optional extensions add Swiss QR-bill invoicing support and functionality for coordinating spontaneous, ad-hoc work assignments beyond the regular volunteer schedule, extending the base platform for organizations with more complex billing or labor coordination needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$juntagrico is free and open source under its published license; there are no paid tiers or per-user fees for the software itself. Organizations can self-host the Django application on their own infrastructure at no licensing cost, giving them full control over data and customization.$q$, $q$Alternatively, CSA organizations that join the Verein Juntagrico association can receive free hosting of a shared instance as part of their membership, avoiding the need to run their own servers while still gaining a say in the software's future development through the association's governance process.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c0d797b-de68-4b90-9beb-fcaefd4f1108', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
