INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Browser-native contract editor$q$, $q$Draft, redline, and negotiate contracts entirely in-browser without exporting to Word or PDF.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$AI-assisted drafting and review$q$, $q$AI suggests clause language, flags risky terms, and accelerates contract generation from templates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Dynamic templates and conditional logic$q$, $q$Templates adapt clauses automatically based on deal parameters like value or jurisdiction.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Configurable approval workflows$q$, $q$Multi-step approval chains route contracts to the right stakeholders automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Native e-signature$q$, $q$Built-in e-signature eliminates the need for a separate signing tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Structured data extraction and repository$q$, $q$AI extracts key terms and dates into a searchable, reportable contract repository.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Self-serve contracting for non-legal teams$q$, $q$Sales, HR, and procurement can generate and send routine contracts within legal-defined guardrails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Integrations$q$, $q$Connects to Slack, Salesforce, HubSpot, and Workday to sync contract data and status.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Browser-native editing removes Word/PDF back-and-forth from contract negotiation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Unlimited-seat pricing avoids per-user cost scaling as adoption grows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$AI-assisted drafting and data extraction speed up both creation and reporting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Strong self-serve workflows for extending contract access to non-legal teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Backed by reputable investors with a clear focus on legal-tech innovation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Pricing is not published and requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Annual contract cost ($15K-$60K/yr) can be high for very small companies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Migrating existing Word-based contract templates requires setup effort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Full value depends on broad org-wide adoption beyond the legal team$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Smaller company size (51-200 employees) versus larger legacy CLM vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$What is Juro used for?$q$, $q$Juro is a contract lifecycle management platform used to create, negotiate, sign, and manage contracts entirely in the browser, with AI assistance and structured data extraction.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$How much does Juro cost?$q$, $q$Juro does not publish self-serve pricing; annual contracts typically range from about $15,000 to $60,000 per year with unlimited user seats included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Who founded Juro?$q$, $q$Juro was founded in 2016 by Richard Mabey and Pavel Kovalevich in London.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Does Juro include e-signature?$q$, $q$Yes, Juro includes native e-signature built into the platform, so contracts can be signed without a separate tool.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$How is Juro different from DocuSign or Ironclad?$q$, $q$Juro is browser-native rather than PDF- or Word-based, and uses unlimited-seat flat pricing instead of per-user fees, differentiating it from DocuSign CLM and Ironclad.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$How much funding has Juro raised?$q$, $q$Juro has raised approximately $36 million in total funding, including a $23 million Series B led by Eight Roads Ventures in January 2022.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Legal team contract turnaround$q$, $q$In-house legal teams use Juro to speed up contract drafting, redlining, and approval cycles.$q$, $q$In-house legal and general counsel teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Sales self-serve contracting$q$, $q$Sales reps generate and send standard order forms or NDAs directly within legal-approved guardrails.$q$, $q$Revenue operations and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$HR and procurement agreements$q$, $q$HR and procurement teams manage employment offers and vendor agreements with automated approval routing.$q$, $q$HR and procurement teams at mid-market companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Scale$q$, $q$Custom pricing (~$15K+/year)$q$, $q$annual$q$, NULL, $q$["Unlimited user seats","Core contract editor and templates","Approval workflows","Native e-signature"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$Enterprise$q$, $q$Custom pricing (up to ~$60K+/year)$q$, $q$annual$q$, NULL, $q$["Everything in Scale","Advanced AI drafting and review","Advanced integrations","Dedicated support and onboarding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Juro is a contract lifecycle management platform built around a browser-native editor rather than the traditional Word-document-plus-email-plus-e-signature workflow most legal teams use. Founded in London in 2016 by Richard Mabey and Pavel Kovalevich, the company has grown into a recognized CLM vendor with engineering based in Riga, Latvia, and a US headquarters opened in Boston in 2025 to support its expanding North American customer base.$q$, $q$Because contracts live natively in the browser rather than as static documents, Juro can layer AI-assisted drafting, structured data extraction, and workflow automation directly onto the contract itself, rather than bolting these capabilities onto a PDF after the fact. This lets legal teams treat contract data as a queryable, reportable asset instead of a filing cabinet of signed documents.$q$, $q$Juro is backed by roughly $36 million in venture funding from investors including Eight Roads, USV, Point Nine Capital, and Seedcamp, with a $23 million Series B closing in January 2022. The company positions itself against both legacy enterprise CLM suites and standalone e-signature tools, emphasizing speed of adoption and unlimited-seat pricing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Juro's browser-native editor supports real-time collaborative drafting and redlining, dynamic templates with conditional clause logic, and AI-assisted contract generation and review that can flag risky terms or suggest clause language during negotiation.$q$, $q$Workflow automation covers configurable multi-step approval chains, built-in native e-signature (no separate DocuSign integration required), and self-serve contracting flows that let non-legal teams like sales or HR generate and send routine contracts within guardrails set by the legal team.$q$, $q$On the data side, Juro extracts structured metadata (parties, dates, values, renewal terms, obligations) from every contract into a searchable repository, enabling reporting, renewal alerts, and integrations with systems like Salesforce, HubSpot, Slack, and Workday so contract status and data flow into the tools other teams already use.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Juro does not publish self-serve, per-seat pricing; instead it sells annual contracts negotiated per customer, typically ranging from roughly $15,000 to $60,000 per year depending on company size, contract volume, and feature tier. Plans are generally referred to as Scale and Enterprise, both of which include unlimited user seats rather than charging per additional user.$q$, $q$This flat, unlimited-seat pricing model is a deliberate contrast to competitors that charge $30-80 per user per month, since Juro's target customers often want to extend contract access broadly across sales, HR, and procurement teams without cost scaling linearly with headcount. Prospective customers request a demo and custom quote directly from Juro's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b3138f4f-7b47-4597-bf67-8ea806a1edd0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
