INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$What is Justworks?$q$, $q$Justworks is a Professional Employer Organization (PEO) that provides payroll, benefits administration, HR compliance tools, and support for small and mid-sized businesses through a co-employment model.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$How much does Justworks cost?$q$, $q$Justworks PEO Basic costs $59 per employee per month and PEO Plus costs $109 per employee per month; an Employer of Record option for international hiring costs $599 per employee per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Who founded Justworks?$q$, $q$Justworks was founded in 2012 by Isaac Oates and is headquartered in New York City.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$What is the difference between PEO Basic and PEO Plus?$q$, $q$PEO Basic includes payroll, compliance, and 401(k) tools, while PEO Plus adds health insurance administration, HSA/FSA accounts, and mental health and fertility benefits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Can Justworks help hire employees internationally?$q$, $q$Yes, Justworks offers an Employer of Record service priced at $599 per employee per month for hiring and paying employees in other countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Does Justworks offer payroll without the PEO model?$q$, $q$Yes, Justworks Payroll is a standalone payroll product for companies that don't need or qualify for full PEO co-employment.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Small business HR outsourcing$q$, $q$Founders without an HR department use Justworks to handle payroll, benefits, and compliance in one platform.$q$, $q$Small business owners and startup founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Startup benefits access$q$, $q$Early-stage companies use PEO co-employment to offer large-group health insurance rates to employees.$q$, $q$Startup HR and operations leads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$International team hiring$q$, $q$US companies use Justworks EOR to legally employ international team members without a foreign entity.$q$, $q$Companies hiring remote international employees$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$PEO Basic$q$, $q$$59/employee/month$q$, $q$monthly$q$, NULL, $q$["Full-service payroll","Contractor payments","Compliance and HR tools","401(k) management","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$PEO Plus$q$, $q$$109/employee/month$q$, $q$monthly$q$, NULL, $q$["Everything in Basic","Health insurance administration","HSA and FSA accounts","Mental health and fertility benefits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Time Tracking Add-on$q$, $q$+$8/employee/month$q$, $q$monthly$q$, NULL, $q$["Time tracking for hourly and salaried staff","Adds to either PEO plan"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$Employer of Record$q$, $q$$599/employee/month$q$, $q$monthly$q$, NULL, $q$["International payroll","International benefits administration","Compliant employment without a foreign entity"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Justworks is a Professional Employer Organization (PEO) founded in 2012 by Isaac Oates and headquartered in New York City. As a PEO, Justworks enters into a co-employment relationship with its client companies' employees, which allows small businesses to pool into large-group health insurance plans and offload payroll tax filing and HR compliance obligations that would otherwise require significant in-house expertise.$q$, $q$The platform combines payroll, benefits administration, compliance support, and HR tools into a single web and mobile interface, aimed specifically at founders and operators running lean teams without a dedicated HR department. Justworks has become known for a simplified, transparent product experience relative to more complex legacy PEOs.$q$, $q$Beyond its core PEO offering, Justworks has expanded its product line to include Justworks Payroll (a standalone payroll product for companies that don't use the PEO model) and an Employer of Record service for hiring employees internationally, broadening its addressable market beyond traditional US-only PEO clients.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Justworks' core PEO service bundles full-service payroll processing (including contractor payments and tax filings), large-group health insurance access, and HR compliance guidance into one subscription, backed by 24/7 customer support for both employers and employees.$q$, $q$Benefits administration covers medical, dental, and vision insurance, HSA and FSA accounts, 401(k) retirement plan management, and access to mental health and fertility benefit programs, all administered through the same platform employees use for payroll and time-off requests.$q$, $q$Additional modules include time tracking (available as an add-on), an Employer of Record service that lets US companies legally employ workers in other countries without setting up a foreign entity, and a standalone payroll-only product (Justworks Payroll) for businesses that don't need or qualify for full PEO co-employment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('938ab555-9fbc-47d8-a414-f6dbfadcc473', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Justworks prices its PEO service per employee per month across two tiers. PEO Basic costs $59 per employee per month and includes payroll, contractor payments, compliance tools, 401(k) management, and 24/7 support. PEO Plus costs $109 per employee per month and adds health insurance administration, HSA/FSA account management, and mental health and fertility benefit access on top of the Basic feature set.$q$, $q$Time tracking can be added to either PEO plan for an additional $8 per employee per month. For companies hiring internationally, Justworks' Employer of Record product is priced separately at $599 per employee per month, covering payroll and benefits administration for employees in other countries without requiring the client to establish a local legal entity.$q$]::text[], 2);
