INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$What is Kajabi used for?$q$, $q$Kajabi is an all-in-one platform for creators to build, market, and sell online courses, coaching, memberships, and communities without combining multiple separate tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$How much does Kajabi cost?$q$, $q$As of Kajabi's January 2026 pricing update, Basic costs $179/month ($143/month annual), Growth costs $249/month ($199/month annual), and Pro costs $499/month ($399/month annual).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Who founded Kajabi?$q$, $q$Kajabi was founded in 2010 in Irvine, California, by Kenny Rueter and Travis Rosser.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Does Kajabi include email marketing?$q$, $q$Yes, Kajabi Marketing provides built-in email and SMS automation and audience segmentation on every plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Is Kajabi good for building communities?$q$, $q$Yes, Kajabi includes native community features alongside courses, though the number of communities allowed depends on the plan tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$How much funding has Kajabi raised?$q$, $q$Kajabi raised a $550 million round in May 2021 led by Tiger Global at a $2 billion valuation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Online course creation and sales$q$, $q$Creators build and sell self-paced courses using Kajabi's no-code product and checkout tools.$q$, $q$Independent online course creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Coaching and membership businesses$q$, $q$Coaches and consultants run recurring membership programs with built-in community and billing.$q$, $q$Coaches and membership site operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Digital product launches$q$, $q$Creators use Kajabi Pipelines to run automated launch funnels for new digital products.$q$, $q$Content creators and digital marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Basic$q$, $q$$179/month ($143/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["5 products","1 community","2,500 contacts","2 admin users","Unlimited funnels and landing pages"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Growth$q$, $q$$249/month ($199/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["50 products","1 community","25,000 contacts","11 admin users","Lower payment processing fees"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Pro$q$, $q$$499/month ($399/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited products","3 communities","100,000 contacts","26 admin users","Lowest payment processing fees"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kajabi is an all-in-one platform that lets creators build, market, and sell digital products, online courses, coaching programs, memberships, communities, podcasts, and digital downloads, without needing to combine separate tools for hosting, email marketing, landing pages, and payments. Founded in 2010 in Irvine, California, by Kenny Rueter and Travis Rosser, the company grew largely through word of mouth in the creator economy before raising outside capital.$q$, $q$In May 2021, Kajabi raised a $550 million round led by Tiger Global at a $2 billion valuation, becoming one of the few unicorns in the creator-tools space. Despite the raise, the company has remained privately held and has continued to expand its product surface into marketing automation, community features, and AI-assisted content tools rather than pursuing acquisitions or a public listing.$q$, $q$The platform's core unit is the 'product', a course, community, podcast, or coaching offer, which creators build using no-code page builders, then sell through Kajabi's built-in checkout, email/SMS marketing, and automated sales funnel ('Pipeline') tools, all under a single subscription and a single customer/contact database.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kajabi Products lets creators structure and host courses, coaching offers, communities, podcasts, and digital downloads using drag-and-drop, no-code builders, with customizable landing pages and checkout flows built into the same platform.$q$, $q$Kajabi Marketing provides email and SMS automation, audience segmentation, and broadcast campaigns, while Kajabi Pipelines offers pre-built, automated sales funnel templates (webinar funnels, product launch funnels, lead magnet funnels) so creators can go from landing page to purchase to onboarding without external funnel software.$q$, $q$Native community features let creators run discussion spaces and group interaction alongside their courses, competing directly with standalone community platforms, while built-in payment processing (Kajabi Payments) and analytics give creators sales and engagement reporting without a separate e-commerce or analytics integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kajabi restructured its pricing in January 2026, its first major pricing change since 2015. The current lineup includes an entry-level tier, Basic at $179/month (or $143/month billed annually) with 5 products, 1 community, 2,500 contacts, and 2 admin users, Growth at $249/month ($199/month annually) with 50 products, 1 community, 25,000 contacts, and 11 admin users, and Pro at $499/month ($399/month annually) with unlimited products, 3 communities, 100,000 contacts, and 26 admin users.$q$, $q$All tiers include unlimited sales funnels, landing pages, marketing emails, and access groups regardless of plan level. Payment processing fees vary by tier: Kajabi's own payment processor charges roughly 2.9%+$0.30 on lower tiers down to 2.7%+$0.30 on Pro, while transaction fees on third-party payment processors scale down from 5% on lower tiers to as low as 0.5% on Pro, incentivizing higher-volume creators to upgrade.$q$]::text[], 2);
