INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$High-performance SIP proxy/registrar$q$, $q$Handles thousands of call setups per second for carrier-grade VoIP routing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$WebRTC and WebSocket support$q$, $q$Native WebSocket transport enables browser-based real-time communication apps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Presence and instant messaging$q$, $q$SIMPLE-based IM and presence with embedded XCAP server and MSRP relay.$q$, 2);
