INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Load balancing and failover$q$, $q$Distributes and reroutes SIP traffic automatically across available endpoints.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Least-cost and DID routing$q$, $q$Built-in routing logic for direct inward dialing and cost-optimized call routing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Broad backend integration$q$, $q$Connects to MySQL, PostgreSQL, Redis, LDAP, MongoDB, Cassandra, and more.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Monitoring and control interfaces$q$, $q$JSON-RPC, XML-RPC, and SNMP support for operational monitoring and management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Proven at massive scale, routing billions of VoIP minutes monthly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Highly configurable and extensible for custom routing logic$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Long operating history and mature, battle-tested codebase since 2001$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Broad backend and protocol integration options$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Steep learning curve requiring SIP and telecom protocol expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$No official vendor support; relies on community or third-party consultants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Configuration syntax can be complex for newcomers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Requires self-hosting and infrastructure management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Best suited to large-scale deployments, overkill for very small setups$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$What is Kamailio used for?$q$, $q$Kamailio is an open-source SIP server used to build large-scale VoIP, WebRTC, presence, and instant-messaging platforms for telecom carriers and service providers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Is Kamailio free?$q$, $q$Yes, Kamailio is completely free and open source under the GPLv2 license with no licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$When was Kamailio created?$q$, $q$Kamailio's history dates to September 2001 as SIP Express Router (SER), later forked into OpenSER in 2005 and renamed Kamailio in 2008.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$How is Kamailio different from Asterisk?$q$, $q$Kamailio focuses on SIP signaling, proxying, and routing at very high scale, while Asterisk is a broader open-source PBX with stronger built-in media handling and call features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$How many calls can Kamailio handle?$q$, $q$Kamailio is designed to process thousands of call setups per second, making it suitable for carrier-grade VoIP deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Does Kamailio support WebRTC?$q$, $q$Yes, Kamailio includes native WebSocket support that enables browser-based WebRTC communication applications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Carrier-grade VoIP routing$q$, $q$Telecom carriers deploy Kamailio as a high-throughput SIP proxy and router for call traffic.$q$, $q$Telecom carriers and VoIP service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$WebRTC communication platforms$q$, $q$Developers build browser-based calling and messaging apps using Kamailio's WebSocket-enabled SIP signaling.$q$, $q$Real-time communication developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Enterprise unified communications$q$, $q$Enterprises build internal SIP-based voice and presence platforms using Kamailio as the signaling core.$q$, $q$Enterprise telecom and IT engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full SIP server source code","Self-hosted deployment","Community support via mailing lists and chat"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kamailio is a free, open-source SIP server used to build large-scale VoIP, WebRTC, presence, and instant-messaging platforms. Its origins date to September 2001, when the project began as SIP Express Router (SER) at Fraunhofer FOKUS, a research institute in Berlin, meaning Kamailio's codebase predates the finalized SIP v2.0 specification (RFC 3261) and its early developers helped shape the protocol's real-world extensions.$q$, $q$The project went through several identity changes: a 2005 fork became OpenSER, which was renamed Kamailio in 2008 following a trademark dispute, and later that year the Kamailio and original SER communities merged their codebases into a single unified project under the Kamailio name. Today it is maintained by a distributed community of contributors rather than a single company.$q$, $q$Released under GPLv2, Kamailio is designed for extreme scale, capable of processing thousands of call setups per second, and is used by telecom carriers and VoIP providers worldwide to route what its maintainers describe as billions of minutes of voice traffic every month.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kamailio's networking layer supports asynchronous TCP, UDP, and SCTP transport with TLS encryption for secure signaling, dual IPv4/IPv6 support, and native WebSocket support for WebRTC-based real-time communication applications.$q$, $q$On the application layer, it provides SIMPLE-based instant messaging and presence with an embedded XCAP server and MSRP relay, IMS extensions for VoLTE deployments, ENUM lookups, DID and least-cost routing, and load balancing with automated failover across SIP endpoints.$q$, $q$Operationally, Kamailio includes built-in accounting, authentication, and authorization modules, integrates with backend systems including MySQL, PostgreSQL, Oracle, Radius, LDAP, Redis, Cassandra, MongoDB, and Memcached, and exposes JSON-RPC/XML-RPC control interfaces plus SNMP monitoring for production operations teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kamailio is entirely free and open source under the GPLv2 license, with no paid tiers, license fees, or vendor lock-in. Anyone can download the source from GitHub, compile it, and deploy it on their own infrastructure without cost.$q$, $q$Because there is no company behind Kamailio, there is no official paid support tier either; organizations that need commercial support typically contract independent consultants or specialist VoIP engineering firms within the Kamailio ecosystem, or rely on community support through the project's mailing lists and IRC/chat channels.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f4e2487-8444-49f1-b4b1-729b8e49b3c9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
