INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$Block storage and private networking$q$, $q$Attachable storage volumes and private network configuration for multi-server architectures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$99.95% uptime SLA$q$, $q$Service-level guarantee covering servers, CPUs, firewalls, load balancers, and storage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$24/7 human technical support$q$, $q$Included support on all paid plans without an additional support-tier fee.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$Highly granular configuration of CPU, RAM, storage, and bandwidth per server$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$Transparent per-minute billing avoids paying for unused capacity$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$30-day free trial with up to $100 in credit for new customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('345f158e-d413-44fa-b795-28721d2c9389', $q$24/7 human support included on all plans, no extra fee$q$, 3);
