-- Enrichment marathon batch: Juicebox, JumpCloud, juntagrico, Juro, Justworks, Kajabi, Kamailio, Kamatera

-- в”Ђв”Ђ Juicebox в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$AI recruiting search engine that uses natural-language queries (PeopleGPT) to find and engage candidates across 800M+ profiles.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free trial, paid plans from $139/seat/month$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Juicebox Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Juicebox (PeopleGPT) review 2026: AI-powered recruiting search, pricing tiers, sourcing agents, ATS integrations, pros, cons and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Juicebox, also widely known by its flagship product name PeopleGPT, is an AI-powered talent sourcing and recruiting search engine founded in 2022 by David Paffenholz (CEO, a Harvard economics graduate who previously worked on growth at Snap) and Ishan Gupta (a former BlueLearn software engineer who left Dartmouth College to build the company). The company launched through Y Combinator's Summer 2022 (S22) batch and is headquartered in San Francisco, California. Juicebox's core innovation is replacing traditional Boolean search strings used by recruiters with natural-language queries: a recruiter types a plain-English description of the ideal candidate, and Juicebox's large-language-model-powered engine translates that into a structured search across a database of more than 800 million professional profiles aggregated from public web and professional network data. Beyond search, Juicebox offers always-on AI sourcing Agents that run in the background, learn from a recruiter's approvals and rejections, continuously refine search criteria, and deliver fresh shortlists without manual re-searching; this Agent capability is sold as a $199-per-agent-per-month add-on on top of any paid plan. The platform also provides automated, personalized outreach sequencing, contact-data enrichment (email and phone numbers unlocked via contact credits), and deep integrations with applicant tracking systems including Greenhouse, Lever, Ashby, Workday, BambooHR, SmartRecruiters, iCIMS, JobAdder, Personio, Oracle Taleo and dozens more. Juicebox has raised a total of roughly $36 million in earlier rounds, including a $30 million Series A led by Sequoia Capital in September 2025 with participation from Y Combinator, and in March 2026 it closed an $80 million Series B led by DST Global (with Sequoia, Coatue, Y Combinator, NFDG and Verified Capital participating) at an $850 million valuation, reporting that annual recurring revenue had tripled since the Series A and that it now serves roughly 5,000 customers ranging from early-stage startups to Fortune 100 companies and leading AI labs (publicly cited users include Ramp and Perplexity). Pricing is structured as a free trial with limited searches, a Starter plan at $139 per seat per month, a Growth plan at $199 per seat per month, and a custom-priced Business plan for larger teams; annual billing brings the effective price down by roughly 15 percent, which is the source of marketing copy advertising plans 'from $119'. All paid plans include unlimited searches and unlimited shortlisted candidates per project, with contact credits metered separately for revealing verified emails and phone numbers. Juicebox targets in-house talent acquisition teams, recruiting agencies, and hiring managers at technology companies who want to source passive candidates faster than manual Boolean search on LinkedIn Recruiter allows. Its most direct competitors are LinkedIn Recruiter (the incumbent, Boolean-search-based sourcing tool), HeroHunt.ai, SeekOut, Fetcher, and other AI-native sourcing tools like hireEZ; Juicebox differentiates primarily through its conversational natural-language search interface, its always-on autonomous Agents that proactively resurface candidates, and its rapid enterprise traction validated by top-tier venture investors within roughly three years of founding.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4cc45ff7-31f0-4735-be09-538439350dbc';

