-- в”Ђв”Ђ juntagrico в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Open-source Python/Django platform for managing community-supported agriculture cooperatives and their members.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$juntagrico Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$juntagrico review 2026: open-source Django software for CSA cooperatives covering member management, shares, deliveries and billing. Features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$juntagrico is a free, open-source software platform purpose-built to manage the administrative operations of Community-Supported Agriculture (CSA) organizations, known in German-speaking Switzerland as 'Solawi' (Solidarische Landwirtschaft). The project originated from internal tooling built for Ortoloco, a Swiss CSA cooperative, and was later generalized and rebuilt starting in 2017 so that other CSA groups could adopt it as a standalone product rather than a one-off internal tool. It is built entirely on Python and the Django web framework, with its source code hosted publicly on GitHub and developed collaboratively by contributors from participating CSA organizations. Governance and ongoing development are coordinated by the Verein Juntagrico (the Juntagrico Association), a nonprofit membership association that gives adopting CSA organizations a formal say in the software's roadmap; the association also offers free hosting of a shared juntagrico instance to its member organizations, while any organization is free to self-host the open-source codebase independently without joining the association or paying license fees. Functionally, juntagrico addresses the operational complexity specific to CSA cooperatives: it manages member registration and administration, tracks cooperative share certificates and financial deposits, administers vegetable/product subscriptions and their sizing, coordinates the mandatory co-worker (volunteer labor) obligations that many CSA models require of members, generates weekly delivery and depot (distribution point) lists, and produces the reporting needed to reconcile subscriptions against harvest capacity. Optional extensions add QR-bill invoicing (aligned to the Swiss QR-invoice payment standard) and tools for coordinating spontaneous, one-off work assignments beyond the standard volunteer schedule. As of recent counts, juntagrico is in production use at more than 25 CSA operations across Switzerland, making it a de facto standard tool in that country's CSA/Solawi movement, alongside comparable community-agriculture software such as OpenOlitor (also Swiss-developed and presented at FOSDEM). Because juntagrico is a volunteer-maintained, association-governed open-source project rather than a venture-backed company, it has no funding history, no headquarters in the corporate sense (the association and its contributor base are Switzerland-based), no pricing tiers, and no company size to report; access to the software itself is free under its open-source license, with the only recurring cost being either self-hosting infrastructure or, for association members, a membership contribution that funds shared hosting and continued development. Its target users are CSA/Solawi cooperatives, community gardens, and similar member-share agricultural organizations, typically newer or growing operations that need structured member, share, and delivery management; established operations with heavily customized processes may find they need developer involvement to adapt juntagrico's Django-based codebase to their specific workflows, since unlike commercial SaaS competitors it offers no vendor support contract by default.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6c0d797b-de68-4b90-9beb-fcaefd4f1108';

